#!/usr/bin/perl

use strict;
use warnings;
use CGI;
use CGI::Carp qw(fatalsToBrowser);
use File::Basename;
use Fcntl ':flock';

my $q = CGI->new;

# Define an allowed directory for log files
# IMPORTANT: This should be a directory that is readable by the web server
# and contains ONLY log files that are safe to display.
# Do NOT use a directory that could contain sensitive scripts or user-uploaded files.
my $log_dir = '/var/log'; # Adjust this path as necessary for your system

print $q->header;
print $q->start_html('Log File Viewer');

my $filename = $q->param('logfile');

if (!$filename) {
    print $q->h1('Log File Viewer');
    print $q->p('Please specify a log file using the "logfile" query parameter.');
    print $q->p('Example: ' . $q->a({href=>'?logfile=syslog'}, '?logfile=syslog'));
    print $q->end_html;
    exit;
}

# Sanitize filename: Only allow basenames, prevent directory traversal
my $basename = basename($filename);

# Construct the full path
my $full_path = File::Spec->catfile($log_dir, $basename);

# Check if the file exists and is within the allowed log directory
# This is a crucial security check.
if (!-f $full_path) {
    print $q->h1('Error');
    print $q->p("Error: File '$filename' not found or is not a regular file.");
    print $q->p("Path attempted: $full_path");
    print $q->end_html;
    exit;
}

# Additional security: Ensure the resolved path is still under $log_dir
# This helps prevent symlink attacks where $basename might be a symlink
# pointing outside $log_dir.
my $realpath = realpath($full_path);
if (!$realpath || !($realpath =~ m/^\Q$log_dir\E\//)) {
    print $q->h1('Error');
    print $q->p("Security Error: Access to '$filename' is denied. File is not within the allowed log directory.");
    print $q->p("Path attempted: $full_path");
    print $q->p("Resolved path: $realpath");
    print $q->end_html;
    exit;
}

print $q->h1("Viewing Log File: $basename");
print $q->pre; # Use <pre> for preserving formatting

if (open(my $fh, '<', $full_path)) {
    # Attempt to get a shared lock for reading
    if (flock($fh, LOCK_SH | LOCK_NB)) {
        while (my $line = <$fh>) {
            print $q->escapeHTML($line); # Escape HTML entities in log content
        }
        flock($fh, LOCK_UN); # Release the lock
    } else {
        print $q->escapeHTML("Warning: Could not obtain a shared lock on $basename. Displaying content without lock.\n");
        seek $fh, 0, 0; # Rewind if flock failed and we want to read anyway
        while (my $line = <$fh>) {
            print $q->escapeHTML($line);
        }
    }
    close $fh;
} else {
    print $q->p("Error: Could not open file '$basename' for reading: $!");
}

print $q->end_pre;
